package com.projectbible.shop.maven.jdbc.mysql.product.presentation;
import com.projectbible.shop.maven.jdbc.mysql.common.api.ApiResponse; import com.projectbible.shop.maven.jdbc.mysql.product.application.ProductQueryService; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import java.util.List; import java.util.Map; import org.springframework.web.bind.annotation.*;
@Tag(name="products") @RestController @RequestMapping("/api/v1/products") public class ProductController { private final ProductQueryService service; public ProductController(ProductQueryService service) { this.service=service; } @Operation(summary="List products") @GetMapping public ApiResponse<List<Map<String,Object>>> list(@RequestParam(required=false) Long categoryId) { List<Map<String,Object>> items=service.list(categoryId); return ApiResponse.success(items,Map.of("page",1,"limit",items.size(),"totalCount",items.size(),"totalPages",1)); } @Operation(summary="Get product detail") @GetMapping("/{productId}") public ApiResponse<Map<String,Object>> one(@PathVariable long productId) { return ApiResponse.success(service.one(productId)); } }
